    @Test
    fun `should throw UserNotFoundException when following user does not exist`() {
        // given
        val followerId = "user-a"
        val followingId = "non-existent-user"

        `when`(userRepository.findById(followerId)).thenReturn(Optional.of(UserEntity(id = followerId)))
        `when`(userRepository.findById(followingId)).thenReturn(Optional.empty())

        // when & then
        assertThrows<UserNotFoundException> {
            followService.followUser(followerId, followingId)
        }
        verify(followRepository, never()).save(any())
    }

